import { forwardRef } from "react";
import type { HTMLAttributes } from "react";
import { clsx } from "clsx";
import * as styles from "./StarRating.css";
import { Text } from "../Text";
import { _Star } from "./components/_Star";

export interface StarRatingCustomProps {
  /**
   * The rating value to display (e.g., "4.4")
   */
  value: string;

  /**
   * Optional review count to display (e.g., 13 will be displayed as "(13)")
   */
  reviewCount?: number | undefined;
}

export interface StarRatingProps
  extends
    Omit<HTMLAttributes<HTMLDivElement>, keyof StarRatingCustomProps>,
    StarRatingCustomProps {}

/**
 * Displays a star rating with an optional review count.
 *
 * **Accessibility:** By default, screen readers will announce only the visible
 * text (e.g., "4.4 (13)"), which lacks context. To provide a meaningful
 * experience, pass an `aria-label` that describes the full meaning:
 *
 * @example
 * <StarRating
 *   value="4.4"
 *   reviewCount={13}
 *   aria-label="Rated 4.4 out of 5 stars, based on 13 reviews"
 * />
 */
export const StarRating = forwardRef<HTMLDivElement, StarRatingProps>(
  ({ value, reviewCount, className, ...props }, ref) => {
    const formattedReviewCount =
      reviewCount !== undefined ? `(${reviewCount})` : undefined;

    return (
      <div ref={ref} className={clsx(styles.starRating, className)} {...props}>
        <_Star aria-hidden="true" />
        <Text variant="body.base.heavy">
          <span>{value}</span>
        </Text>
        {formattedReviewCount && (
          <Text variant="body.base.normal">
            <span>{formattedReviewCount}</span>
          </Text>
        )}
      </div>
    );
  }
);

StarRating.displayName = "StarRating";
