import type { HTMLAttributes } from "react";
import { clsx } from "clsx";
import * as styles from "./_Star.css";
import { _BaseIcon } from "../../Icon/_BaseIcon";
import StarIcon from "@fortawesome/fontawesome-pro/svgs/solid/star.svg";

export interface StarProps extends HTMLAttributes<HTMLSpanElement> {}

/**
 * @internal
 * Base star icon component - a 16×16px component using _BaseIcon with the star icon.
 * This is an internal primitive for use within the StarRating component.
 */
export const _Star = ({ className, ...props }: StarProps) => {
  return (
    <_BaseIcon size={16} className={clsx(styles.star, className)} {...props}>
      <StarIcon />
    </_BaseIcon>
  );
};

_Star.displayName = "_Star";
